#!/usr/bin/env python3
import os, subprocess
print('Fixing backend...')
open('package.json','w').write('{\n  "name": "ratan-jewellers-backend",\n  "version": "1.0.0",\n  "description": "Ratan Jewellers Backend API - Node.js + MongoDB",\n  "main": "dist/server.js",\n  "scripts": {\n    "dev": "ts-node src/server.ts",\n    "build": "tsc",\n    "start": "node dist/server.js",\n    "seed": "ts-node src/seed.ts",\n    "seed:staff": "ts-node src/seedStaff.ts",\n    "seed:all": "ts-node src/seed.ts && ts-node src/seedStaff.ts"\n  },\n  "dependencies": {\n    "mongoose": "^8.2.1",\n    "axios": "^1.6.7",\n    "bcryptjs": "^2.4.3",\n    "cors": "^2.8.5",\n    "dotenv": "^16.4.5",\n    "express": "^4.18.3",\n    "express-rate-limit": "^7.2.0",\n    "express-validator": "^7.0.1",\n    "helmet": "^7.1.0",\n    "jsonwebtoken": "^9.0.2",\n    "multer": "^1.4.5-lts.1",\n    "nodemailer": "^6.9.12",\n    "razorpay": "^2.9.2",\n    "uuid": "^9.0.1",\n    "winston": "^3.12.0"\n  },\n  "devDependencies": {\n    "@types/bcryptjs": "^2.4.6",\n    "@types/cors": "^2.8.17",\n    "@types/express": "^4.17.21",\n    "@types/jsonwebtoken": "^9.0.6",\n    "@types/multer": "^1.4.11",\n    "@types/node": "^20.11.28",\n    "@types/nodemailer": "^6.4.14",\n    "@types/uuid": "^9.0.8",\n    "ts-node": "^10.9.2",\n    "typescript": "^5.4.2"\n  }\n}')
open('src/models/User.ts','w').write("import mongoose, { Document, Schema } from 'mongoose';\n\nexport type UserRole = 'CUSTOMER' | 'SALES_STAFF' | 'INVENTORY_MANAGER' | 'STORE_MANAGER' | 'ADMIN' | 'SUPER_ADMIN';\n\nexport interface IUser extends Document {\n  _id: mongoose.Types.ObjectId;\n  email: string; phone?: string; passwordHash?: string;\n  name: string; role: UserRole; isActive: boolean; isVerified: boolean;\n  avatar?: string; googleId?: string; lastLogin?: Date;\n  createdAt: Date; updatedAt: Date;\n}\n\nconst UserSchema = new Schema<IUser>({\n  email:        { type: String, required: true, unique: true, lowercase: true, trim: true },\n  phone:        { type: String, unique: true, sparse: true, trim: true },\n  passwordHash: { type: String },\n  name:         { type: String, required: true, trim: true },\n  role:         { type: String, enum: ['CUSTOMER','SALES_STAFF','INVENTORY_MANAGER','STORE_MANAGER','ADMIN','SUPER_ADMIN'], default: 'CUSTOMER' },\n  isActive:     { type: Boolean, default: true },\n  isVerified:   { type: Boolean, default: false },\n  avatar:       { type: String },\n  googleId:     { type: String, unique: true, sparse: true },\n  lastLogin:    { type: Date },\n}, { timestamps: true });\n\n\nexport const User = mongoose.models.User || mongoose.model<IUser>('User', UserSchema);\n")
print('Running seed:staff...')
subprocess.run(['npm','run','seed:staff'], check=True)
print('')
print('Done! All staff accounts seeded into MongoDB.')